  _hidden = false;
  removeClass(_header, CSS.headerHidden);
  setAttr(_header, 'aria-hidden', 'false'); // ensure visibility is announced
  liveRegion.announce(STRINGS.headerShown || 'Header shown'); // announce
  emit(_header, 'header:show');
}
