Line 1027:     ].filter(Boolean).join(' ')}
Line 1028:     tabIndex={activeFilter === tab.value ? 0 : -1}
Line 1029:     aria-pressed={activeFilter === tab.value}
Line 1030:     onClick={() => onChange(tab.value)}
